import fs from 'node:fs';
import path from 'node:path';
import { LlamaCloudClient } from '@llamaindex/llama-cloud';

async function main() {
  const args = process.argv.slice(2);
  let inputPath = '';
  let outputPath = '';

  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--input' && args[i + 1]) {
      inputPath = args[i + 1];
      i++;
    } else if (args[i] === '--output' && args[i + 1]) {
      outputPath = args[i + 1];
      i++;
    }
  }

  if (!inputPath || !outputPath) {
    console.error('Usage: npx tsx parse.ts --input <pdf_path> --output <md_path>');
    process.exit(1);
  }

  const apiKey = process.env.LLAMA_CLOUD_API_KEY;
  if (!apiKey) {
    console.error('Error: LLAMA_CLOUD_API_KEY environment variable is not set.');
    process.exit(1);
  }

  if (!fs.existsSync(inputPath)) {
    console.error(`Error: Input file does not exist: ${inputPath}`);
    process.exit(1);
  }

  const client = new LlamaCloudClient({
    apiKey: apiKey,
  });

  try {
    const fileStream = fs.createReadStream(inputPath);

    // Using the client to parse the PDF
    // Based on implementation hints: client.parsing.parse({...})
    const result = await client.parsing.uploadFile(fileStream, {
        // We might need to upload first or use a combined call if available.
        // Checking the SDK structure typically involves upload then parse or a direct parse with file.
    });

    // Wait, let's refine based on the hint: "client.parsing.parse({...}) blocks until the job is finished"
    // and "returns a result object that exposes the per-page markdown when you pass expand: ["markdown"]"

    // Actually, looking at the @llamaindex/llama-cloud SDK, the parsing.parse method 
    // often takes a file or an already uploaded file ID.

    const parseResult = await client.parsing.parse({
      file: fs.createReadStream(inputPath),
      // version: "latest" and agentic tier as suggested
      parsingConfig: {
        parsingMode: 'agentic',
      },
      // expand: ["markdown"] to get per-page markdown
    }, {
        // Some SDKs use second arg for options like expand
    });

    // Re-evaluating the SDK call based on typical LlamaCloud SDK patterns
    // Let's use the most direct way suggested by the hint.
  } catch (error) {
    console.error('Error during parsing:', error);
    process.exit(1);
  }
}

