import fs from 'node:fs';
import path from 'node:path';
import { LlamaCloudClient } from '@llamaindex/llama-cloud';

async function main() {
  const args = process.argv.slice(2);
  let inputPath = '';
  let outputPath = '';

  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--input' && args[i + 1]) {
      inputPath = args[i + 1];
      i++;
    } else if (args[i] === '--output' && args[i + 1]) {
      outputPath = args[i + 1];
      i++;
    }
  }

  if (!inputPath || !outputPath) {
    console.error('Usage: npx tsx parse.ts --input <pdf_path> --output <md_path>');
    process.exit(1);
  }

  const apiKey = process.env.LLAMA_CLOUD_API_KEY;
  if (!apiKey) {
    console.error('Error: LLAMA_CLOUD_API_KEY environment variable is not set.');
    process.exit(1);
  }

  if (!fs.existsSync(inputPath)) {
    console.error(`Error: Input file does not exist: ${inputPath}`);
    process.exit(1);
  }

  const client = new LlamaCloudClient({
    apiKey: apiKey,
  });

  try {
    const result = await client.parsing.parse({
      tier: 'agentic',
      version: 'latest',
      upload_file: fs.createReadStream(inputPath),
      expand: ['markdown']
    });

    if (!result.markdown || !result.markdown.pages) {
      console.error('Error: No markdown content returned from LlamaCloud.');
      process.exit(1);
    }

    const pages = result.markdown.pages;
    const markdownContent = pages
      .map((page: any) => {
        if (page.success) {
          return page.markdown;
        }
        return '';
      })
      .join('\n\n');

    // Create intermediate directories if they do not exist
    const outputDir = path.dirname(outputPath);
    if (!fs.existsSync(outputDir)) {
      fs.mkdirSync(outputDir, { recursive: true });
    }

    fs.writeFileSync(outputPath, markdownContent);

    console.log(`Parsed ${pages.length} pages to ${outputPath}`);
    process.exit(0);
  } catch (error) {
    console.error('Error during parsing:', error);
    process.exit(1);
  }
}

main();

